const express = require('express');
const session = require('express-session');
const jwt = require('jsonwebtoken');
const { Issuer, generators } = require('openid-client');

const nonce = generators.nonce();
const codeVerifier = generators.codeVerifier();

const app = express();
app.use(session({
  secret: 'secret-key',
  saveUninitialized: true,
  resave: true
}));

let client;
let tokenSet;

Issuer.discover('https://your-oidc-provider.com') // replace with your provider
  .then((issuer) => {
    client = new issuer.Client({
      client_id: 'client-id', // replace with your client id
      client_secret: 'client-secret', // replace with your client secret
      redirect_uris: ['http://localhost:9000/callback'],
      response_types: ['code'],
    });
  });

app.get('/login', (req, res) => {
  const authUrl = client.authorizationUrl({
    scope: 'openid email profile',
    nonce,
    code_challenge: generators.codeChallenge(codeVerifier),
    code_challenge_method: 'S256',
  });
  res.redirect(authUrl);
});

app.get('/callback', async (req, res) => {
  const params = client.callbackParams(req);
  const callbackResponse = await client.callback('http://localhost:9000/callback', params, { code_verifier: codeVerifier, nonce });
  tokenSet = callbackResponse;
  const idTokenClaims = tokenSet.claims();
  req.session.user = { sub: idTokenClaims.sub, email: idTokenClaims.email, name: idTokenClaims.name };
  res.redirect('/home');
});

app.get('/home', (req, res) => {
  if (!req.session.user) {
    return res.status(401).send('Unauthorized');
  }
  res.send(`Welcome ${req.session.user.name}`);
});

